	// KT - STRY0058367:  2.2 PATCH 6 - FEB-26-2020
	/*
	As a "Task Owner" or "Assigned Member" of a parent task, upon filling out the new sub task form, The "Task Owner" field on the new sub task form should default to:
	• If parent task is unassigned: the Task Parent Originator (Created by field)
	• If parent task is assigned: the Task Parent Assigned Member
 	*/
	setSubTaskTaskOwner: function(){

		var task_owner = "";
		var parent_sys_id = this.getParameter('sysparm_parent');

		var grTaskParent = new GlideRecord('x_153465_discovert_route_task_instance');
		grTaskParent.addQuery("sys_id",parent_sys_id);
		grTaskParent.query();

		if (grTaskParent.next()) {

			if(grTaskParent.state == "-5" || grTaskParent.getValue('assigned_to') == null){ //Unassigned
				// STRY0078378 - if task owner of parent not set, set the owner of the subtask to the originator of the parent
				if (grTaskParent.getValue('u_task_requester') == null){
					task_owner = grTaskParent.getValue('originator');	
				} else {
					task_owner = grTaskParent.getValue('u_task_requester');	
				}

			}

			if(grTaskParent.state == "1" || grTaskParent.getValue('assigned_to') != null){ //Assigned
				task_owner = grTaskParent.getValue('assigned_to');
			}
		}

		return task_owner;
	},

	// KT - STRY0048914:  2.2 PATCH 6 - FEB-26-2020
	/*
	As a user that can create subtasks, Parent Task Owner or Parent Assigned Member, upon filling out the new sub task form, I want the "instruction" field to be EDITABLE when it is in a "new" state, so that I can provide updated Instructions to the assigned member of the sub task. 
	*/
	checkUserIsAssignedMemberORTaskOwner: function(){

		var UserIsAssignedMemberORTaskOwner = false;
		var currentUser = gs.getUser();
		var parent_sys_id = this.getParameter('sysparm_parent');

		var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
		grTask.addQuery("sys_id",parent_sys_id);
		grTask.query();

		while(grTask.next()){
			if(grTask.assigned_to == currentUser.getID() || grTask.u_task_requester == currentUser.getID()){
				UserIsAssignedMemberORTaskOwner = true;
			}
			return UserIsAssignedMemberORTaskOwner;
		}
	},

	//MK-STRY0052581
	updateTaskStateToComplete: function(){
		var task_sysID = (this.getParameter('sysparm_sysId'));
		var set_state = new GlideRecord("x_153465_discovert_route_task_instance");
		if(set_state.get(task_sysID)){
			set_state.state = 3;
			set_state.work_notes = 'Task was marked as Read';
			set_state.update();
		}
	},

	taskParentHasSubtasks: function(){
		var parentID = this.getParameter("parentID");
		var data ;
		var gr = new GlideRecord('x_153465_discovert_route_task_instance');
		gr.addQuery('sys_id',parentID);
		gr.query();

		while(gr.next()){
			data = gr.calchaschildren;
		}
		return data;
	},

	taskGetTaskSysId: function(){
		var suggested_task_number = this.getParameter("suggested_task_sys_id");
		var gr = new GlideRecord('x_153465_discovert_route_task_instance');
		gr.addQuery('suggested_task',suggested_task_number);
		gr.query();

		var new_task_id;

		while(gr.next()){
			new_task_id = gr.sys_id;
		}
		return new_task_id;
	},

	getTaskInfo: function(){
		var user = this.getParameter("currentUser");
		var currentOu = this.getParameter("currentOu");
		var currentTask = this.getParameter("currentTask");
		var taskInfo = new GlideRecord('x_153465_discovert_route_task_instance');
		taskInfo.addQuery('sys_id',currentTask);
		taskInfo.query();
		var viewer="user";
		var state = '';
		var isOuTa = this.IsUserTaskingAuthority(user,currentOu);
		while(taskInfo.next()){
			state = taskInfo.getValue('state');
			if(taskInfo.getValue('assigned_to') == user){
				viewer = 'assigned_to';
			}
			if(taskInfo.getValue('originator') == user){
				viewer = 'originator';
			}
			if(taskInfo.getValue('u_task_requester') == user){
				viewerClientTaskInfo = 'task_owner';
			}
			if(taskInfo.getValue('u_reviewer') == user){
				viewerClientTaskInfo = 'u_reviewer';
			}
			if(isOuTa){
				viewerClientTaskInfo = 'outa';
			}
			if(gs.getUser().hasRole("x_153465_discovert.tasker_global_Tasking_Authority_member_admin")){
				viewer = 'gta';
			}
		}

